class CMPhysicsJudger:
    def __init__(
        self,
    ):
        super().__init__()
        self.judger_name = "cmphysics_judger"

    async def judge(self, data_item: List[RLDataFlowItem]) -> List[RLJudgerResponseItem]:
        response_future = [self.judge_single(d) for d in data_item]
        judger_responses = await asyncio.gather(*response_future)
        return judger_responses
    async def judge_single(self, data_item: RLDataFlowItem) -> RLJudgerResponseItem:
        if data_item.env.rollout.finish_reason not in ["finished", "stop"]:
            return RLJudgerResponseItem(uid=data_item.uid.observation_id, reward={"score": 0})
        response = data_item.env.rollout.response.split("</think>")[-1].replace("<|im_end|>", "").strip()
        # only keep last 10 lines
        num_lines = len(response.split("\n"))
        if num_lines > 10:
            response = "\n".join(response.split("\n")[-10:])
        if len(response) > 1000:
            response = response[-1000:]

        extrat_response = extract_boxed_text_overlap(response)
        if extrat_response is None:
            return RLJudgerResponseItem(uid=data_item.uid.observation_id, reward={"score": 0})
        ground_truths = data_item.data.reward_model["ground_truth"]
        val_type = data_item.data.extra_info["type"]

        loop = asyncio.get_running_loop()
        verify_fn = partial(SEED, extrat_response, ground_truths, val_type)
        try:
            score, rel_dist, tree_size, dist = await asyncio.wait_for(
                loop.run_in_executor(None, verify_fn),
                timeout=10.0,  # 比如 1.0 / 2.0 秒
            )
            reward = float(score) / 100
            print(f"[CMPhysics] [reward] {reward}")
        except asyncio.TimeoutError:
            print(f"[CMPhysics] [Timeout]")
            reward = 0
        except Exception as e:
            print(f"[CMPhysics] [Error]: {e}")
            reward = 0
        return RLJudgerResponseItem(uid=data_item.uid.observation_id, reward={"score": reward})
